typedef enum SDL_IOStatus
{
 SDL_IO_STATUS_READY, /**< تعاد هذه القيمة عندما تكون READY هي الحالة الفعلية في حالة مجرى SDL_IO، وعند ظهورها يعتمد SDL أو التطبيق هذا المسار في المعالجة اللاحقة. */
 SDL_IO_STATUS_ERROR, /**< تعاد هذه القيمة عندما تكون ERROR هي الحالة الفعلية في حالة مجرى SDL_IO، وعند ظهورها يعتمد SDL أو التطبيق هذا المسار في المعالجة اللاحقة. */
 SDL_IO_STATUS_EOF, /**< تعاد هذه القيمة عندما تكون EOF هي الحالة الفعلية في حالة مجرى SDL_IO، وعند ظهورها يعتمد SDL أو التطبيق هذا المسار في المعالجة اللاحقة. */
 SDL_IO_STATUS_NOT_READY, /**< تعاد هذه القيمة عندما تكون NOT READY هي الحالة الفعلية في حالة مجرى SDL_IO، وعند ظهورها يعتمد SDL أو التطبيق هذا المسار في المعالجة اللاحقة. */
 SDL_IO_STATUS_READONLY, /**< تعاد هذه القيمة عندما تكون READONLY هي الحالة الفعلية في حالة مجرى SDL_IO، وعند ظهورها يعتمد SDL أو التطبيق هذا المسار في المعالجة اللاحقة. */
 SDL_IO_STATUS_WRITEONLY /**< تعاد هذه القيمة عندما تكون WRITEONLY هي الحالة الفعلية في حالة مجرى SDL_IO، وعند ظهورها يعتمد SDL أو التطبيق هذا المسار في المعالجة اللاحقة. */
} SDL_IOStatus;
